function split_all_data(t){var d=document.getElementById("split_txt_input"),i=document.getElementById("split_txt_output");if(d&&d.value){d=d.value.split(/[, \n\t]+/);if(d)if("234D"===t){let n=new Set,e=new Set,r=new Set,t=(d.forEach(t=>{t=t.trim();t&&(4===t.length?(r.add(t.charAt(0)),e.add(t.charAt(1)),n.add(t.substring(t.length-2))):3===t.length?(e.add(t.charAt(0)),n.add(t.substring(t.length-2))):2===t.length&&n.add(t))}),"");0<r.size&&(t+="Càng 4D ("+r.size+" số): "+Array.from(r).sort().join(",")+"\n\n"),0<e.size&&(t+="Càng 3D ("+e.size+" số): "+Array.from(e).sort().join(",")+"\n\n"),0<n.size&&(t+="Dàn 2D ("+n.size+" số):\n"+Array.from(n).sort().join(",")),i&&(i.value=t.trim())}else if("ABC"===t){let n=new Set,e=new Set,r=new Set,t=(d.forEach(t=>{t=t.trim();t&&(4===t.length?(n.add(t.substring(0,2)),e.add(t.substring(1,3)),r.add(t.substring(2,4))):3===t.length&&(n.add(t.substring(0,2)),e.add(t.substring(1,3))))}),"Dàn AB ("+n.size+" số):\n"+Array.from(n).sort().join(",")+"\n\nDàn BC ("+e.size+" số):\n"+Array.from(e).sort().join(",")+"\n\n");0<r.size?t+="Dàn CD ("+r.size+" số):\n"+Array.from(r).sort().join(","):t+="Dàn CD (0 số):",i&&(i.value=t.trim())}}}function join_AB(){var t=document.getElementById("td3d_cang_input"),n=document.getElementById("td3d_dan_input"),d=document.getElementById("td3d_txt_output");if(t&&n&&d){t=t.value.split(/[, \n\t]+/);let e=n.value.split(/[, \n\t]+/),r=new Set;t.forEach(t=>{let n=t.trim();n&&e.forEach(t=>{t=t.trim();t&&(1===n.length?r.add(n+t):2===n.length&&2<=t.length&&n.charAt(1)===t.charAt(0)&&r.add(n+t.substring(1)))})});n=Array.from(r).sort(),t=(d.value=n.join(","),document.getElementById("td3d_txt_outputcount"));t&&(t.innerText=n.length+" số",t.hidden=0===n.length)}}